<template>
  <div class="image-comparison-container">
    <div class="image-wrapper">
      <img :src="beforeImage" alt="Before" class="image before-image" />
      <div class="slider" :style="{ width: sliderWidth + '%' }">
        <img :src="afterImage" alt="After" class="image after-image" />
      </div>
      <div 
        class="slider-handle" 
        :style="{ left: sliderWidth + '%' }"
        @mousedown="startDragging"
        @touchstart="startDragging"
      >
        <div class="handle-icon">
          <span class="arrow left-arrow"></span>
          <span class="arrow right-arrow"></span>
        </div>
      </div>
    </div>
    <input 
      type="range" 
      min="0" 
      max="100" 
      v-model="sliderWidth" 
      class="slider-input" 
      @input="updateSlider"
    />
  </div>
</template>

<script>
export default {
  props: {
    beforeImage: {
      type: String,
      required: true
    },
    afterImage: {
      type: String,
      required: true
    }
  },
  data() {
    return {
      sliderWidth: 50,
      isDragging: false
    };
  },
  methods: {
    updateSlider(event) {
      this.sliderWidth = event.target.value;
    },
    startDragging(event) {
      this.isDragging = true;
      document.addEventListener('mousemove', this.onDrag);
      document.addEventListener('mouseup', this.stopDragging);
      document.addEventListener('touchmove', this.onDrag);
      document.addEventListener('touchend', this.stopDragging);
    },
    onDrag(event) {
      if (!this.isDragging) return;
      const rect = this.$el.getBoundingClientRect();
      const clientX = event.touches ? event.touches[0].clientX : event.clientX;
      const newSliderWidth = ((clientX - rect.left) / rect.width) * 100;
      this.sliderWidth = Math.min(100, Math.max(0, newSliderWidth));
    },
    stopDragging() {
      this.isDragging = false;
      document.removeEventListener('mousemove', this.onDrag);
      document.removeEventListener('mouseup', this.stopDragging);
      document.removeEventListener('touchmove', this.onDrag);
      document.removeEventListener('touchend', this.stopDragging);
    }
  }
};
</script>

