<template>
  <div id="app">
    <div class="puzzle-container">
      <h1 class="text-center">拼照片遊戲</h1>
      <div v-if="!gameStarted">
        <div class="full-image" :style="{ backgroundImage: `url(${imageSrc})` }"></div>
        <div class="difficulty-selection">
          <label for="difficulty">選擇難度:</label>
          <select id="difficulty" v-model="difficulty">
            <option value="easy">簡單</option>
            <option value="medium">中等</option>
            <option value="hard">困難</option>
          </select>
        </div>
        <button class="btn btn-primary" @click="startGame">開始遊戲</button>
        <p class="progress-hint mt-2">在時間內如果可以把照片拼湊完成，將可以挑戰成功喔～！</p>
      </div>
      <div v-else>
        <div class="game-info">
          <p>剩餘時間: {{ formattedTime }}</p>
        </div>
        <div class="puzzle-board">
          <div
            v-for="(piece, index) in shuffledPieces"
            :key="index"
            :style="getPieceStyle(piece)"
            class="puzzle-piece"
            @click="movePiece(index)"
          >
            <span v-if="showNumber && piece !== emptyPieceIndex">{{ piece }}</span>
          </div>
        </div>
        <div v-if="gameOver" class="game-over">
          <h2>{{ gameResultMessage }}</h2>
          <div v-if="gameWon">
            <a href="https://studio.d-id.com/share?id=ef202c745169167f4c11101c670342fd&utm_source=copy" target="_blank" class="btn btn-success">
               前方神秘小月台，有人有話想對妳說~
            </a>
          </div>
          <button class="btn btn-primary" @click="resetGame">再玩一次</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'PuzzleGame',
  data() {
    return {
      gameStarted: false,
      gameOver: false,
      gameWon: false,
      timeLeft: 60, // 1 分鐘
      timer: null,
      gameResultMessage: '',
      imageSrc: require('@/assets/二訪.jpg'), // 使用本地圖片
      difficulty: 'medium', // 默認難度為中等
      rows: 3, // 固定為 3 行
      cols: 3, // 固定為 3 列
      pieces: [],
      shuffledPieces: [],
      showNumber: false,
      emptyPieceIndex: null,
    };
  },
  computed: {
    formattedTime() {
      const minutes = Math.floor(this.timeLeft / 60);
      const seconds = this.timeLeft % 60;
      return `${minutes}:${seconds < 10 ? '0' : ''}${seconds}`;
    }
  },
  methods: {
    startGame() {
      this.gameStarted = true;
      this.gameOver = false;
      this.gameWon = false;
      this.timeLeft = 60;
      this.initializePieces();
      this.shufflePieces();
      this.startTimer();
    },
    startTimer() {
      this.timer = setInterval(() => {
        if (this.timeLeft > 0) {
          this.timeLeft--;
        } else {
          this.endGame(false);
        }
      }, 1000);
    },
    endGame(won) {
      clearInterval(this.timer);
      this.gameOver = true;
      this.gameWon = won;
      this.gameResultMessage = won ? '恭喜破關！' : '遊戲失敗！';
      if (won) {
        this.playCelebrationSound();
      } else {
        this.playFailureSound();
      }
    },
    resetGame() {
      this.gameStarted = false;
      this.gameOver = false;
      this.gameWon = false;
      clearInterval(this.timer);
    },
    initializePieces() {
      this.pieces = Array.from({ length: this.rows * this.cols }, (_, i) => i);
      this.shuffledPieces = [...this.pieces];
      this.emptyPieceIndex = this.pieces.length - 1; // 設置最後一塊為空白塊
    },
    shufflePieces() {
      let shuffleSteps;
      if (this.difficulty === 'easy') {
        shuffleSteps = 5;
      } else if (this.difficulty === 'medium') {
        shuffleSteps = 10;
      } else if (this.difficulty === 'hard') {
        shuffleSteps = 20;
      }
      for (let i = 0; i < shuffleSteps; i++) {
        const emptyIndex = this.shuffledPieces.indexOf(this.emptyPieceIndex);
        const possibleMoves = this.getPossibleMoves(emptyIndex);
        const move = possibleMoves[Math.floor(Math.random() * possibleMoves.length)];
        [this.shuffledPieces[emptyIndex], this.shuffledPieces[move]] = [this.shuffledPieces[move], this.shuffledPieces[emptyIndex]];
      }
    },
    getPossibleMoves(emptyIndex) {
      const moves = [];
      const row = Math.floor(emptyIndex / this.cols);
      const col = emptyIndex % this.cols;

      if (row > 0) moves.push(emptyIndex - this.cols); // 上
      if (row < this.rows - 1) moves.push(emptyIndex + this.cols); // 下
      if (col > 0) moves.push(emptyIndex - 1); // 左
      if (col < this.cols - 1) moves.push(emptyIndex + 1); // 右

      return moves;
    },
    getPieceStyle(piece) {
      const width = 100 / this.cols;
      const height = 100 / this.rows;
      const row = Math.floor(piece / this.cols);
      const col = piece % this.cols;
      return {
        width: `${width}%`,
        height: `${height}%`,
        backgroundImage: piece !== this.emptyPieceIndex ? `url(${this.imageSrc})` : 'none',
        backgroundSize: `${this.cols * 100}% ${this.rows * 100}%`,
        backgroundPosition: `${(col / (this.cols - 1)) * 100}% ${(row / (this.rows - 1)) * 100}%`,
        order: this.shuffledPieces.indexOf(piece),
      };
    },
    movePiece(index) {
      const emptyIndex = this.shuffledPieces.indexOf(this.emptyPieceIndex);
      if (this.isAdjacent(index, emptyIndex)) {
        [this.shuffledPieces[index], this.shuffledPieces[emptyIndex]] = [this.shuffledPieces[emptyIndex], this.shuffledPieces[index]];
        if (this.isSolved()) {
          this.endGame(true);
        }
      }
    },
    isAdjacent(index1, index2) {
      const row1 = Math.floor(index1 / this.cols);
      const col1 = index1 % this.cols;
      const row2 = Math.floor(index2 / this.cols);
      const col2 = index2 % this.cols;
      return (Math.abs(row1 - row2) + Math.abs(col1 - col2)) === 1;
    },
    isSolved() {
      return this.shuffledPieces.every((piece, index) => piece === index);
    },
    playCelebrationSound() {
      const audio = new Audio('/celebration-sound.mp3');
      audio.play().catch(error => {
        console.log('Audio playback failed:', error);
      });
    },
    playFailureSound() {
      const audio = new Audio('/failure-sound.mp3');
      audio.play().catch(error => {
        console.log('Audio playback failed:', error);
      });
    }
  }
};
</script>

