<template>
  <div class="container mt-5">
    <!-- 標題 -->
    <h1 class="text-center main-title mb-4 rainbow-text">Unna Birthday Journey</h1>

    <button class="btn btn-primary mb-3 w-100" @click="startScan">掃描 QR 碼 (按兩次)</button>
    
    <!-- 新增選擇照片按鈕 -->
    <div class="mb-3">
      <input 
        type="file" 
        accept="image/*" 
        ref="fileInput" 
        style="display: none" 
        @change="onFileSelected"
      >
      <button class="btn btn-success w-100" @click="openFileInput">
        從相簿選擇 QR 碼圖片
      </button>
    </div>

    <div v-if="scanning" id="reader" class="mb-3"></div>
    <div class="d-flex justify-content-between align-items-center mb-3">
      <h2 class="cc mb-0">Unna生日旅程-卡片列表</h2>
      <button 
        class="btn btn-danger"
        @click="clearList"
        v-if="cards.length > 0"
      >
        清除列表
      </button>
    </div>
    <ul class="list-group">
      <li 
        class="list-group-item" 
        v-for="(card, index) in cards" 
        :key="card.id" 
        @click="viewCard(card.id)"
        style="cursor: pointer; height: 50px;"
      >
        {{ index + 1 }}. {{ card.title }}
      </li>
    </ul>
    <p class="cc mb-1 mt-3">Unna生日旅程進化進度表:</p>
    <div class="progress mt-3">
      <div 
        class="progress-bar" 
        role="progressbar" 
        :style="{ width: progress + '%' }" 
        :aria-valuenow="progress" 
        aria-valuemin="0" 
        aria-valuemax="100"
      >
        {{ progress }}%
      </div>
    </div>

    <!-- 進度提示文字 -->
    <p class="progress-hint mt-2">當進度累積到一定的進度時，不時會有一些特殊驚喜喔～！</p>

    <!-- 挑戰遊戲連結 -->
    <div v-if="progress >= 50" class="youtube-link mt-3">
      <router-link to="/puzzle-game" class="btn btn-danger">
        <i class="fas fa-gamepad"></i> 恭喜，妳解鎖成功，可以前進挑戰自己~
      </router-link>
    </div>

    <!-- 特殊成就和動畫區塊 -->
    <div class="special-achievement-section mt-5">
      
      <!-- 成就展示區 -->
      <div class="achievement-display-section">
        <h3 class="mb-4">成就展示區</h3>
        <div v-if="showBadge29" class="achievement-badge">
          🎖️ 獲得成就：29歲徽章
        </div>
        <div v-if="showBadge30" class="achievement-badge">
          🏆 獲得成就：30歲徽章
        </div>
      </div>

      <!-- 恭喜動畫 -->
      <div v-if="showCongratsAnimation" class="congrats-animation">
        🎉 恭喜達到33%進度！
      </div>

      <!-- 完成動畫 -->
      <div v-if="showCompletionAnimation" class="completion-animation">
        🎉 恭喜完成所有收集！
            <!-- 新增圖片比較容器 -->
            <div class="mt-5">
              <div class="text-center">烏納-進化完成！</div>
              <ImageComparisonContainer 
                :beforeImage="beforeImage" 
                :afterImage="afterImage"
              />
            </div>
      </div>
    </div>


    <!-- 開發者署名 -->
    <div class="developer-signature">
      <p>Developed with ❤️ by John</p>
    </div>
    
    <router-link to="/" class="btn btn-secondary mt-3">返回首頁</router-link>
  </div>
  <br/><br/><br/>
</template>

<script>
import { Html5Qrcode } from 'html5-qrcode';
import jsQR from 'jsqr';
import ImageComparisonContainer from '../components/ImageComparisonContainer.vue';

export default {
  components: {
    ImageComparisonContainer
  },
  data() {
    return {
      cards: [],
      beforeImage: require('../assets/LINE_1.jpg'),
      afterImage: require('../assets/tt.png'),
      scanning: false,
      showBadge29: false,
      showBadge30: false,
      showCongratsAnimation: false,
      showCompletionAnimation: false,
      allCards: [
        { id: '烏納30歲生日祝福的旅程', title: '烏納30歲生日祝福的旅程' },
        { id: '29歲的成長', title: '29歲的成長' },
        { id: '30歲的願望清單', title: '30歲的願望清單' },
        { id: '30歲的生日禮物', title: '30歲的生日禮物' },
        { id: '30歲美好的晚餐', title: '30歲美好的晚餐' },
        { id: '美好時光影片大放送', title: '美好時光影片大放送' },
        { id: '30歲的生日快樂歌', title: '30歲的生日快樂歌' },
        { id: '30歲第一時間的祝福', title: '30歲第一時間的祝福' },
        { id: '30歲第一個主日的祝福', title: '30歲第一個主日的祝福' },
        { id: '30歲來至很多親朋好友的生日祝福', title: '30歲來至很多親朋好友的生日祝福' },
        { id: 'Diana的生日祝福', title: 'Diana的生日祝福' },
        { id: '維良的生日祝福', title: '維良的生日祝福' },
        { id: 'Ivy的生日祝福', title: 'Ivy的生日祝福' },
        { id: 'Karen的生日祝福', title: 'Karen的生日祝福' },
        { id: 'Esther的生日祝福', title: 'Esther的生日祝福' },
        { id: '凱哥的生日祝福', title: '凱哥的生日祝福' },
        { id: 'Alex的生日祝福', title: 'Alex的生日祝福' },
      ],
    };
  },
  computed: {
    progress() {
      return Math.round((this.cards.length / this.allCards.length) * 100);
    }
  },
  watch: {
    progress(newValue) {
      if (newValue >= 33 && !this.showBadge29) {
        this.showBadge29 = true;
        this.showCongratsAnimation = true;
        this.playAchievementSound();
        setTimeout(() => {
          this.showCongratsAnimation = false;
        }, 3000); // 恭喜動畫顯示3秒
      }
      
      if (newValue >= 100 && !this.showCompletionAnimation) {
        this.showCompletionAnimation = true;
        this.showBadge30 = true;
        this.playCelebrationSound();
        this.showCelebrationAnimation();
      }
    }
  },
  methods: {
    startScan() {
      this.scanning = true;
      const html5QrCode = new Html5Qrcode("reader");
      html5QrCode.start(
        { facingMode: "environment" },
        {
          fps: 10,
          qrbox: 250
        },
        (decodedText, decodedResult) => {
          this.scanning = false;
          html5QrCode.stop();
          this.addCard(decodedText);
        },
        (errorMessage) => {
          console.warn(`QR Code no match: ${errorMessage}`);
        }
      ).catch((err) => {
        console.error(`Unable to start scanning, error: ${err}`);
      });
    },

    openFileInput() {
      this.$refs.fileInput.click();
    },
    
    async onFileSelected(event) {
      const file = event.target.files[0];
      if (!file) return;

      try {
        const imageData = await this.getImageData(file);
        const code = jsQR(imageData.data, imageData.width, imageData.height);
        
        if (code) {
          this.addCard(code.data);
        } else {
          alert("未能在圖片中找到有效的QR碼");
        }
      } catch (error) {
        console.error("QR Code scan error:", error);
        alert("處理圖片時發生錯誤，請重試");
      } finally {
        event.target.value = '';
      }
    },

    getImageData(file) {
      return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const context = canvas.getContext('2d');
          canvas.width = img.width;
          canvas.height = img.height;
          context.drawImage(img, 0, 0);
          try {
            const imageData = context.getImageData(0, 0, canvas.width, canvas.height);
            resolve(imageData);
          } catch (e) {
            reject(e);
          }
        };
        img.onerror = reject;
        img.src = URL.createObjectURL(file);
      });
    },

    addCard(id) {
      const cardExists = this.cards.some(card => card.id === id);
      const validCard = this.allCards.find(card => card.id === id);

      if (!cardExists && validCard) {
        const newCard = { id, title: validCard.title };
        this.cards.push(newCard);
        localStorage.setItem('cards', JSON.stringify(this.cards));
        this.$router.push(`/card/${id}`);
      } else if (!validCard) {
        alert("無效的卡片 ID，無法加入列表");
      } else {
        alert("此卡片已存在於列表中");
      }
    },

    viewCard(id) {
      this.$router.push(`/card/${id}`);
    },

    clearList() {
      if (confirm('確定要清除所有卡片嗎？此操作無法復原。')) {
        this.cards = [];
        localStorage.removeItem('cards');
      }
    },

    playAchievementSound() {
      const audio = new Audio('/achievement-sound.mp3');
      audio.play().catch(error => {
        console.log('Audio playback failed:', error);
      });
    },

    playCelebrationSound() {
      const audio = new Audio('/celebration-sound.mp3');
      audio.play().catch(error => {
        console.log('Audio playback failed:', error);
      });
    },

    showCelebrationAnimation() {
      import('canvas-confetti').then(confetti => {
        confetti.default({
          particleCount: 100,
          spread: 70,
          origin: { y: 0.6 }
        });
      });
    }
  },
  mounted() {
    const savedCards = JSON.parse(localStorage.getItem('cards')) || [];
    this.cards = savedCards;
  },
};
</script>

